54	
55	        for (int i = 0; i < shardCount; i++) {
56	            String shardId = String.format("shardId-%012d", i);
57	            stream.getShards().add(new KinesisShard(shardId, "0", "340282366920938463463374607431768211455", "0"));
58	        }
59	
60	        store.put(storageKey, stream);
61	        LOG.infov("Created Kinesis stream: {0} in region {1} with {2} shards", streamName, region, shardCount);
62	        return stream;
63	    }
