185	    public void splitShard(String streamName, String shardId, String newStartingHashKey, String region) {
186	        KinesisStream stream = resolveStream(streamName, region);
187	        KinesisShard parent = stream.getShards().stream()
188	                .filter(s -> s.getShardId().equals(shardId))
189	                .findFirst()
190	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Shard " + shardId + " not found", 400));
191	
192	        if (parent.isClosed()) {
193	            throw new AwsException("InvalidArgumentException", "Shard " + shardId + " is already closed", 400);
194	        }
195	
196	        parent.setClosed(true);
197	        parent.setSequenceNumberRange(new KinesisShard.SequenceNumberRange(
198	                parent.getSequenceNumberRange().startingSequenceNumber(),
199	                String.valueOf(sequenceGenerator.get())));
200	
201	        String start = parent.getHashKeyRange().startingHashKey();
202	        String end = parent.getHashKeyRange().endingHashKey();
203	
204	        KinesisShard child1 = new KinesisShard(nextShardId(stream), start, subtractOne(newStartingHashKey), String.valueOf(sequenceGenerator.get()));
205	        child1.setParentShardId(shardId);
206	
207	        KinesisShard child2 = new KinesisShard(nextShardId(stream), newStartingHashKey, end, String.valueOf(sequenceGenerator.get()));
208	        child2.setParentShardId(shardId);
209	
210	        stream.getShards().add(child1);
211	        stream.getShards().add(child2);
212	        store.put(regionKey(region, streamName), stream);
213	        LOG.infov("Split shard {0} in stream {1}", shardId, streamName);
214	    }
215	
216	    public void mergeShards(String streamName, String shardId, String adjacentShardId, String region) {
217	        KinesisStream stream = resolveStream(streamName, region);
218	        KinesisShard shard1 = stream.getShards().stream()
219	                .filter(s -> s.getShardId().equals(shardId))
220	                .findFirst()
221	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Shard " + shardId + " not found", 400));
222	        KinesisShard shard2 = stream.getShards().stream()
223	                .filter(s -> s.getShardId().equals(adjacentShardId))
224	                .findFirst()
225	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Shard " + adjacentShardId + " not found", 400));
226	
227	        if (shard1.isClosed() || shard2.isClosed()) {
228	            throw new AwsException("InvalidArgumentException", "One or both shards are already closed", 400);
229	        }
230	
231	        shard1.setClosed(true);
232	        shard2.setClosed(true);
233	        String seq = String.valueOf(sequenceGenerator.get());
234	        shard1.setSequenceNumberRange(new KinesisShard.SequenceNumberRange(shard1.getSequenceNumberRange().startingSequenceNumber(), seq));
235	        shard2.setSequenceNumberRange(new KinesisShard.SequenceNumberRange(shard2.getSequenceNumberRange().startingSequenceNumber(), seq));
236	
237	        // Combine hash ranges (assuming they are adjacent)
238	        java.math.BigInteger s1Start = new java.math.BigInteger(shard1.getHashKeyRange().startingHashKey());
239	        java.math.BigInteger s2Start = new java.math.BigInteger(shard2.getHashKeyRange().startingHashKey());
240	        
241	        String start = s1Start.min(s2Start).toString();
242	        java.math.BigInteger s1End = new java.math.BigInteger(shard1.getHashKeyRange().endingHashKey());
243	        java.math.BigInteger s2End = new java.math.BigInteger(shard2.getHashKeyRange().endingHashKey());
244	        String end = s1End.max(s2End).toString();
245	
246	        KinesisShard child = new KinesisShard(nextShardId(stream), start, end, seq);
247	        child.setParentShardId(shardId);
248	        child.setAdjacentParentShardId(adjacentShardId);
249	
250	        stream.getShards().add(child);
251	        store.put(regionKey(region, streamName), stream);
252	        LOG.infov("Merged shards {0} and {1} in stream {2}", shardId, adjacentShardId, streamName);
253	    }
254	
255	    private String nextShardId(KinesisStream stream) {
256	        return String.format("shardId-%012d", stream.getShards().size());
257	    }
258	
259	    private String subtractOne(String val) {
260	        return new java.math.BigInteger(val).subtract(java.math.BigInteger.ONE).toString();
261	    }
262	
263	    public String putRecord(String streamName, byte[] data, String partitionKey, String region) {
264	        KinesisStream stream = resolveStream(streamName, region);
265	        KinesisShard shard = selectShard(stream, partitionKey);
266	        
267	        String sequenceNumber = String.valueOf(sequenceGenerator.incrementAndGet());
268	        KinesisRecord record = new KinesisRecord(data, partitionKey, sequenceNumber, Instant.now());
269	        
270	        shard.getRecords().add(record);
271	        store.put(regionKey(region, streamName), stream);
272	        
273	        return sequenceNumber;
274	    }
275	
276	    public String getShardIterator(String streamName, String shardId, String type, String sequenceNumber, String region) {
277	        resolveStream(streamName, region); // validate exists
278	        // Format: streamName|shardId|type|sequenceNumber|index
279	        String raw = String.format("%s|%s|%s|%s|%d", 
280	                streamName, shardId, type, sequenceNumber != null ? sequenceNumber : "", 0);
281	        return Base64.getEncoder().encodeToString(raw.getBytes(StandardCharsets.UTF_8));
282	    }
283	
284	    public Map<String, Object> getRecords(String shardIterator, Integer limit, String region) {
285	        byte[] decoded = Base64.getDecoder().decode(shardIterator);
286	        String[] parts = new String(decoded, StandardCharsets.UTF_8).split(java.util.regex.Pattern.quote("|"), 5);
287	        if (parts.length < 5) throw new AwsException("InvalidArgumentException", "Invalid shard iterator", 400);
288	
289	        String streamName = parts[0];
290	        String shardId = parts[1];
291	        String type = parts[2];
292	        String startSeq = parts[3];
293	        int lastIndex = Integer.parseInt(parts[4]);
294	
295	        KinesisStream stream = resolveStream(streamName, region);
296	        KinesisShard shard = stream.getShards().stream()
297	                .filter(s -> s.getShardId().equals(shardId))
298	                .findFirst()
299	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Shard not found", 400));
300	
301	        List<KinesisRecord> allRecords = shard.getRecords();
302	        int startIndex = 0;
303	
304	        // Simple implementation of iterator types
305	        if ("TRIM_HORIZON".equals(type)) {
306	            startIndex = lastIndex;
307	        } else if ("LATEST".equals(type)) {
308	            startIndex = allRecords.size();
309	        } else if ("AT_SEQUENCE_NUMBER".equals(type)) {
310	            for (int i = 0; i < allRecords.size(); i++) {
311	                if (allRecords.get(i).getSequenceNumber().equals(startSeq)) {
312	                    startIndex = i;
313	                    break;
314	                }
315	            }
316	        } else if ("AFTER_SEQUENCE_NUMBER".equals(type)) {
317	             for (int i = 0; i < allRecords.size(); i++) {
318	                if (allRecords.get(i).getSequenceNumber().equals(startSeq)) {
319	                    startIndex = i + 1;
320	                    break;
321	                }
322	            }
323	        }
324	
325	        int max = limit != null ? Math.min(limit, 1000) : 1000;
326	        List<KinesisRecord> result = new ArrayList<>();
327	        int nextIndex = startIndex;
328	        for (int i = startIndex; i < allRecords.size() && result.size() < max; i++) {
329	            result.add(allRecords.get(i));
330	            nextIndex = i + 1;
331	        }
332	
333	        String nextIterator = Base64.getEncoder().encodeToString(
334	                String.format("%s|%s|%s|%s|%d", streamName, shardId, "TRIM_HORIZON", "", nextIndex)
335	                .getBytes(StandardCharsets.UTF_8));
336	
337	        Map<String, Object> response = new HashMap<>();
338	        response.put("Records", result);
339	        response.put("NextShardIterator", nextIterator);
340	        response.put("MillisBehindLatest", Math.max(0, allRecords.size() - nextIndex));
341	        return response;
342	    }
343	
344	    private KinesisStream resolveStream(String streamName, String region) {
345	        return store.get(regionKey(region, streamName))
346	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Stream " + streamName + " not found", 400));
347	    }
348	
349	    private KinesisShard selectShard(KinesisStream stream, String partitionKey) {
350	        // Simple hash-based shard selection among ALL shards, then resolve to open one
351	        int index = Math.abs(partitionKey.hashCode()) % stream.getShards().size();
352	        KinesisShard shard = stream.getShards().get(index);
353	        
354	        // If closed, find the first open child (simplified)
355	        while (shard.isClosed()) {
356	            KinesisShard finalShard = shard;
357	            shard = stream.getShards().stream()
358	                    .filter(s -> finalShard.getShardId().equals(s.getParentShardId()) || finalShard.getShardId().equals(s.getAdjacentParentShardId()))
359	                    .filter(s -> !s.isClosed())
360	                    .findFirst()
361	                    .orElse(shard); // Fallback to itself if no open child found
362	            if (shard == finalShard) break; // prevent infinite loop
363	        }
364	        return shard;
365	    }
366	
367	    private String regionKey(String region, String name) {
368	        return region + "::" + name;
369	    }
370	}
